create table atendentes (ativo boolean not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, telefone varchar(20), created_by varchar(100), email varchar(100) not null unique, modified_by varchar(100), nome varchar(100) not null, senha varchar(255) not null, tipo_usuario varchar(255) not null check (tipo_usuario in ('CLIENTE','ATENDENTE','COZINHA','GERENTE','ADMIN')), primary key (id));
create table categoria_produtos (ativo boolean not null, ordem integer not null, created_at timestamp(6) not null, id bigserial not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, slug varchar(80) not null, created_by varchar(100), modified_by varchar(100), nome varchar(150) not null, descricao TEXT, primary key (id), constraint uk_categoria_produto_tenant_slug unique (tenant_id, slug));
create table clientes (ativo boolean not null, telefone_verificado boolean not null, created_at timestamp(6) not null, id bigserial not null, otp_expiration timestamp(6), updated_at timestamp(6), version bigint, otp_code varchar(10), telefone varchar(20) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(100), tipo_usuario varchar(255) not null check (tipo_usuario in ('CLIENTE','ATENDENTE','COZINHA','GERENTE','ADMIN')), primary key (id));
create table configuracao_financeira_event_log (flag_anterior boolean, flag_novo boolean, valor_anterior numeric(14,2), valor_novo numeric(14,2), entidade_id bigint, id bigserial not null, timestamp timestamp(6) not null, usuario_role varchar(50) not null, entidade_tipo varchar(60), tipo_evento varchar(60) not null, usuario_nome varchar(100) not null, detalhe varchar(500), motivo varchar(500), primary key (id));
create table configuracao_financeira_sistema (limite_pos_pago numeric(10,2) not null, pos_pago_ativo boolean not null, valor_minimo_operacao numeric(10,2) not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, atualizado_por_role varchar(50), atualizado_por_nome varchar(100), created_by varchar(100), modified_by varchar(100), motivo_ultima_alteracao varchar(500), primary key (id));
create table cozinhas (ativa boolean not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('CENTRAL','BAR_PREP','CONFEITARIA','GRILL','PIZZARIA','SUSHI','ESPECIAL')), impressora_id varchar(50), created_by varchar(100), modified_by varchar(100), nome varchar(100) not null, descricao varchar(500), primary key (id));
create table dispositivos_operacionais (activation_code_expires_at timestamp(6), ativado_em timestamp(6), created_at timestamp(6) not null, device_token_issued_at timestamp(6), device_token_revoked_at timestamp(6), id bigserial not null, instituicao_id bigint not null, revogado_em timestamp(6), tenant_id bigint not null, ultimo_heartbeat_em timestamp(6), unidade_atendimento_id bigint, updated_at timestamp(6), version bigint, platform varchar(30), status varchar(30) not null check (status in ('PENDENTE_ATIVACAO','ATIVO','SUSPENSO','REVOGADO','EXPIRADO')), tipo varchar(30) not null check (tipo in ('POS','KDS','CHECKOUT','COZINHA','BAR','BALCAO','QUIOSQUE','ADMIN','OUTRO')), app_version varchar(40), codigo varchar(60) not null, activation_code_hash varchar(64), device_token_hash varchar(64), serial_hash varchar(64), ultimo_ip varchar(64), fabricante varchar(80), modelo_dispositivo varchar(80), created_by varchar(100), modified_by varchar(100), nome varchar(120) not null, user_agent varchar(255), primary key (id));
create table eventos_sessao (created_at timestamp(6) not null, id bigserial not null, sessao_consumo_id bigint not null, updated_at timestamp(6), version bigint, tipo_evento varchar(50) not null check (tipo_evento in ('SESSAO_ABERTA','MESA_VINCULADA','MESA_DESVINCULADA','CLIENTE_VINCULADO','PEDIDO_CRIADO','FUNDO_RECARREGADO','FUNDO_DEBITADO','PAGAMENTO_SOLICITADO','SESSAO_ENCERRADA','SESSAO_EXPIRADA_AUTOMATICAMENTE','OUTRO')), created_by varchar(100), modified_by varchar(100), descricao TEXT, usuario_responsavel varchar(255), primary key (id));
create table fundos_consumo (ativo boolean not null, saldo_atual numeric(19,2), created_at timestamp(6) not null, id bigserial not null, sessao_consumo_id bigint not null unique, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), primary key (id));
create table instituicoes (ativa boolean not null, created_at timestamp(6) not null, id bigserial not null, otp_expiration timestamp(6), tenant_id bigint not null, updated_at timestamp(6), version bigint, otp_code varchar(10), sigla varchar(10) not null unique, telefone_autorizacao varchar(20) not null, nif varchar(50) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(150) not null, url_logo varchar(500), primary key (id));
create table itens_pedido (preco_unitario numeric(10,2) not null, quantidade integer not null check (quantidade>=1), subtotal numeric(10,2) not null, created_at timestamp(6) not null, id bigserial not null, pedido_id bigint, produto_id bigint not null, sub_pedido_id bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), observacoes varchar(500), primary key (id));
create table mesas (ativa boolean not null, capacidade integer, numero integer, created_at timestamp(6) not null, id bigserial not null, instituicao_id bigint, tenant_id bigint not null, unidade_atendimento_id bigint not null, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('MESA_FISICA','QUARTO','AREA_EVENTO','ESPACO_LOUNGE','VIRTUAL')), created_by varchar(100), modified_by varchar(100), qr_code varchar(100) unique, referencia varchar(100) not null, primary key (id));
create table pagamento_callback_logs (processed boolean not null, signature_valid boolean, created_at timestamp(6) not null, id bigserial not null, pagamento_id bigint, processed_at timestamp(6), received_at timestamp(6) not null, tenant_id bigint, updated_at timestamp(6), version bigint, external_reference varchar(15), processing_status varchar(30) not null check (processing_status in ('RECEIVED','PROCESSED','IGNORED_DUPLICATE','FAILED','INVALID_SIGNATURE','PAYMENT_NOT_FOUND')), provider varchar(30) not null, status_recebido varchar(40), created_by varchar(100), gateway_charge_id varchar(100), modified_by varchar(100), processing_error varchar(500), headers_json TEXT, payload_json TEXT, raw_body TEXT, primary key (id));
create table pagamento_event_log (id bigserial not null, pagamento_id bigint, pedido_id bigint, timestamp timestamp(6) not null, ip varchar(50), role varchar(50) not null, tipo_evento varchar(50) not null check (tipo_evento in ('PAGAMENTO_CRIADO','CONFIRMACAO_PAGAMENTO','CALLBACK_RECEBIDO','AUTORIZACAO_POS_PAGO','NEGACAO_POS_PAGO','ESTORNO_MANUAL','ESTORNO_AUTOMATICO','POLITICA_POS_PAGO_ATIVADA','POLITICA_POS_PAGO_DESATIVADA','RECARGA_FUNDO','PAGAMENTO_FALHOU')), usuario varchar(100) not null, motivo varchar(500), dados_adicionais TEXT, primary key (id));
create table pagamentos_gateway (amount numeric(10,2) not null, cliente_id bigint, confirmed_at timestamp(6), created_at timestamp(6) not null, fundo_consumo_id bigint, id bigserial not null, pedido_id bigint, tenant_id bigint not null, updated_at timestamp(6), version bigint, entidade varchar(10), external_reference varchar(15) unique, metodo varchar(20) check (metodo in ('GPO','REF')), referencia varchar(20), status varchar(20) not null check (status in ('PENDENTE','CONFIRMADO','FALHOU','ESTORNADO')), tipo_pagamento varchar(20) not null check (tipo_pagamento in ('PRE_PAGO','POS_PAGO')), created_by varchar(100), gateway_charge_id varchar(100), modified_by varchar(100), observacoes varchar(500), gateway_response TEXT, primary key (id));
create table pedido_event_log (created_at timestamp(6) not null, id bigserial not null, pedido_id bigint not null, timestamp timestamp(6) not null, ip_origem varchar(50), usuario varchar(100), observacoes varchar(500), status_anterior varchar(255) check (status_anterior in ('CRIADO','EM_ANDAMENTO','FINALIZADO','CANCELADO')), status_novo varchar(255) not null check (status_novo in ('CRIADO','EM_ANDAMENTO','FINALIZADO','CANCELADO')), primary key (id));
create table pedido_sequence_counters (data_referencia date not null, created_at timestamp(6) not null, id bigserial not null, proximo_numero bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), primary key (id));
create table pedidos (total numeric(10,2), created_at timestamp(6) not null, id bigserial not null, pago_em timestamp(6), sessao_consumo_id bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, status varchar(20) not null check (status in ('CRIADO','EM_ANDAMENTO','FINALIZADO','CANCELADO')), status_financeiro varchar(20) not null check (status_financeiro in ('NAO_PAGO','PENDENTE_PAGAMENTO','PAGO','ESTORNADO')), tipo_pagamento varchar(20) not null check (tipo_pagamento in ('PRE_PAGO','POS_PAGO')), created_by varchar(100), modified_by varchar(100), observacoes varchar(500), numero varchar(255) not null unique, primary key (id));
create table planos (ativo boolean not null, max_dispositivos integer not null, max_instituicoes integer not null, max_produtos integer not null, max_qr_codes integer not null, max_unidades_atendimento integer not null, max_usuarios integer not null, permite_multi_instituicao boolean not null, permite_offline boolean not null, permite_pedidos_qr boolean not null, permite_pos boolean not null, preco_mensal numeric(12,2) not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, codigo varchar(30) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(120) not null, descricao TEXT, primary key (id));
create table produtos (ativo boolean not null, disponivel boolean not null, preco numeric(10,2) not null, tempo_preparo_minutos integer, categoria_produto_id bigint not null, created_at timestamp(6) not null, id bigserial not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, categoria varchar(30) not null check (categoria in ('ENTRADA','PRATO_PRINCIPAL','ACOMPANHAMENTO','SOBREMESA','BEBIDA_ALCOOLICA','BEBIDA_NAO_ALCOOLICA','LANCHE','PIZZA','OUTROS')), codigo varchar(50) not null, created_by varchar(100), modified_by varchar(100), nome varchar(150) not null, descricao varchar(500), url_imagem varchar(500), primary key (id), constraint idx_produto_tenant_codigo unique (tenant_id, codigo));
create table provisioning_templates (ativo boolean not null, created_at timestamp(6) not null, id bigserial not null, updated_at timestamp(6), version bigint, tipo_tenant varchar(40) not null check (tipo_tenant in ('VENDEDOR_RUA','RESTAURANTE','BAR','FOOD_COURT','EVENTO','LOJA','CLUBE','INSTITUCIONAL')), codigo varchar(60) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(120) not null, descricao varchar(500), configuracao_json TEXT, primary key (id));
create table public_qr_order_requests (created_at timestamp(6) not null, id bigserial not null, pedido_id bigint, qr_code_operacional_id bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, status varchar(20) not null check (status in ('PROCESSING','COMPLETED','FAILED')), request_hash varchar(64) not null, created_by varchar(100), idempotency_key varchar(100) not null, modified_by varchar(100), primary key (id));
create table public_qr_payment_requests (created_at timestamp(6) not null, id bigserial not null, pagamento_id bigint, pedido_id bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, status varchar(20) not null check (status in ('PROCESSING','COMPLETED','FAILED')), request_hash varchar(64) not null, created_by varchar(100), idempotency_key varchar(100) not null, modified_by varchar(100), primary key (id));
create table qr_code_tokens (created_at timestamp(6) not null, expira_em timestamp(6) not null, id bigserial not null, instituicao_id bigint, mesa_id bigint, pedido_id bigint, updated_at timestamp(6), usado_em timestamp(6), version bigint, status varchar(20) not null check (status in ('ATIVO','USADO','EXPIRADO','CANCELADO')), tipo varchar(20) not null check (tipo in ('MESA','ENTREGA','PAGAMENTO')), token varchar(36) not null unique, created_by varchar(100), modified_by varchar(100), usado_por varchar(100), metadados TEXT, primary key (id));
create table qr_codes_operacionais (ativo boolean not null, revogado boolean not null, created_at timestamp(6) not null, id bigserial not null, instituicao_id bigint not null, mesa_id bigint, revogado_em timestamp(6), tenant_id bigint not null, unidade_atendimento_id bigint, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('TENANT_GERAL','INSTITUICAO','UNIDADE_ATENDIMENTO','MESA','BALCAO','TAKEAWAY','DELIVERY','EVENTO','QUIOSQUE')), token varchar(64) not null unique, created_by varchar(100), modified_by varchar(100), nome varchar(120), primary key (id));
create table rotas_producao_categoria (ativo boolean not null, prioridade integer not null, atualizado_em timestamp(6), categoria_produto_id bigint not null, created_at timestamp(6) not null, criado_em timestamp(6) not null, id bigserial not null, tenant_id bigint not null, unidade_producao_id bigint not null, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), primary key (id));
create table sessoes_consumo (modo_anonimo boolean not null, aberta_em timestamp(6) not null, atendente_id bigint, cliente_id bigint, created_at timestamp(6) not null, fechada_em timestamp(6), id bigserial not null, instituicao_id bigint, mesa_id bigint, tenant_id bigint not null, ultima_atividade_em timestamp(6) not null, unidade_atendimento_id bigint, updated_at timestamp(6), version bigint, tipo_sessao varchar(20) not null check (tipo_sessao in ('PRE_PAGO','POS_PAGO')), status varchar(30) not null check (status in ('ABERTA','AGUARDANDO_PAGAMENTO','ENCERRADA','EXPIRADA')), qr_code_sessao varchar(36) not null unique, created_by varchar(100), modified_by varchar(100), primary key (id));
create table sub_pedidos (total numeric(10,2), cozinha_id bigint not null, created_at timestamp(6) not null, entregue_em timestamp(6), id bigserial not null, iniciado_em timestamp(6), pedido_id bigint not null, pronto_em timestamp(6), recebido_em timestamp(6), tenant_id bigint not null, unidade_atendimento_id bigint not null, unidade_producao_id bigint, updated_at timestamp(6), version bigint, status varchar(20) not null check (status in ('CRIADO','PENDENTE','EM_PREPARACAO','PRONTO','ENTREGUE','CANCELADO')), numero varchar(50) not null unique, created_by varchar(100), modified_by varchar(100), responsavel_entrega varchar(100), responsavel_preparo varchar(100), observacoes varchar(500), primary key (id));
create table subpedido_event_log (cozinha_id bigint not null, created_at timestamp(6) not null, id bigserial not null, subpedido_id bigint not null, tempo_transacao_ms bigint, timestamp timestamp(6) not null, ip_origem varchar(50), usuario varchar(100), observacoes varchar(500), status_anterior varchar(255) check (status_anterior in ('CRIADO','PENDENTE','EM_PREPARACAO','PRONTO','ENTREGUE','CANCELADO')), status_novo varchar(255) not null check (status_novo in ('CRIADO','PENDENTE','EM_PREPARACAO','PRONTO','ENTREGUE','CANCELADO')), primary key (id));
create table subscricoes (fim_em date, inicio_em date not null, renovacao_automatica boolean not null, created_at timestamp(6) not null, id bigserial not null, plano_id bigint not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, estado varchar(20) not null check (estado in ('ATIVA','EXPIRADA','SUSPENSA','CANCELADA')), created_by varchar(100), modified_by varchar(100), primary key (id));
