create table tenant_limite_overrides (ativo boolean not null, max_dispositivos integer, max_instituicoes integer, max_produtos integer, max_qr_codes integer, max_unidades_atendimento integer, max_usuarios integer, configurado_em timestamp(6), created_at timestamp(6) not null, id bigserial not null, tenant_id bigint not null, updated_at timestamp(6), version bigint, created_by varchar(100), modified_by varchar(100), configurado_por varchar(120), motivo varchar(500), primary key (id));
