create table unidade_cozinha (cozinha_id bigint not null, unidade_id bigint not null);
create table unidades_atendimento (ativa boolean not null, created_at timestamp(6) not null, id bigserial not null, instituicao_id bigint, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('RESTAURANTE','BAR','CAFETERIA','ROOM_SERVICE','EVENTO','PISCINA','LOUNGE')), created_by varchar(100), modified_by varchar(100), nome varchar(100) not null, descricao varchar(500), primary key (id));
create table unidades_consumo (capacidade integer, modo_anonimo boolean not null, numero integer, aberta_em timestamp(6) not null, atendente_id bigint, cliente_id bigint, created_at timestamp(6) not null, fechada_em timestamp(6), id bigserial not null, unidade_atendimento_id bigint not null, updated_at timestamp(6), version bigint, status varchar(30) not null check (status in ('DISPONIVEL','OCUPADA','AGUARDANDO_PAGAMENTO','FINALIZADA')), tipo varchar(30) not null check (tipo in ('MESA_FISICA','QUARTO','AREA_EVENTO','ESPACO_LOUNGE','VIRTUAL')), created_by varchar(100), modified_by varchar(100), qr_code varchar(100) unique, referencia varchar(100) not null, primary key (id));
create table unidades_producao (ativo boolean not null, ordem integer not null, atualizado_em timestamp(6), created_at timestamp(6) not null, criado_em timestamp(6) not null, id bigserial not null, instituicao_id bigint not null, tenant_id bigint not null, unidade_atendimento_id bigint, updated_at timestamp(6), version bigint, tipo varchar(30) not null check (tipo in ('COZINHA','BAR','PASTELARIA','CHURRASQUEIRA','BALCAO','EXPEDICAO','QUIOSQUE','COPA','OUTRO')), codigo varchar(40) not null, created_by varchar(100), modified_by varchar(100), nome varchar(120) not null, primary key (id));
create table user_roles (user_id bigint not null, role varchar(255) check (role in ('ROLE_CLIENTE','ROLE_ATENDENTE','ROLE_GERENTE','ROLE_COZINHA','ROLE_ADMIN')));
create table users (ativo boolean not null, created_at timestamp(6) not null, id bigserial not null, ultimo_acesso timestamp(6), unidade_atendimento_id bigint, updated_at timestamp(6), version bigint, telefone varchar(20) not null unique, username varchar(50) not null unique, created_by varchar(100), email varchar(100) unique, modified_by varchar(100), nome_completo varchar(150), password varchar(255) not null, primary key (id));
